#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PI 3.1415926535897932
#define M 2147483647
#define A 1103515245
#define C 12345

inline double roundDouble(double value) {
    return (double)((int)value);
}

inline double randu_kernel(__global int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs((double)seed[index] / (double)M);
}

inline double randn_kernel(__global int *seed, int index) {
    double u = randu_kernel(seed, index);
    double v = randu_kernel(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

__kernel void likelihood_kernel(__global double *arrayX,
                                __global double *arrayY,
                                __global double *xj,
                                __global double *yj,
                                __global double *CDF,
                                __global int *ind,
                                __global int *objxy,
                                __global double *likelihood,
                                __global unsigned char *I,
                                __global double *u,
                                __global double *weights,
                                int Nparticles,
                                int countOnes,
                                int max_size,
                                int k,
                                int IszY,
                                int Nfr,
                                __global int *seed,
                                __global double *partial_sums,
                                __local double *local_sums) {
    int gid = (int)get_global_id(0);
    if (gid >= Nparticles) return;

    (void)CDF;
    (void)u;
    (void)local_sums;

    arrayX[gid] = xj[gid] + 1.0 + 5.0 * randn_kernel(seed, gid);
    arrayY[gid] = yj[gid] + (-2.0) + 2.0 * randn_kernel(seed, gid);

    double like = 0.0;
    for (int y = 0; y < countOnes; y++) {
        int indX = (int)roundDouble(arrayX[gid]) + objxy[y * 2 + 1];
        int indY = (int)roundDouble(arrayY[gid]) + objxy[y * 2];
        int idx = indX * IszY * Nfr + indY * Nfr + k;
        if (idx < 0) idx = -idx;
        if (idx >= max_size) idx = 0;
        ind[gid * countOnes + y] = idx;

        int pix = (int)I[idx];
        int d1 = pix - 100;
        int d2 = pix - 228;
        like += ((double)(d1 * d1) - (double)(d2 * d2)) / 50.0;
    }
    like = like / (double)countOnes;
    likelihood[gid] = like;

    weights[gid] = weights[gid] * exp(like);
    partial_sums[gid] = weights[gid];
}

