#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define M 2147483647
#define A 1103515245
#define C 12345

inline double randu_kernel(__global int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs((double)seed[index] / (double)M);
}

__kernel void sum_kernel(__global double *partial_sums, int Nparticles) {
    int gid = (int)get_global_id(0);
    if (gid != 0) return;

    double s = 0.0;
    for (int i = 0; i < Nparticles; i++) {
        s += partial_sums[i];
    }
    partial_sums[0] = s;
}

__kernel void normalize_weights_kernel(__global double *weights,
                                       int Nparticles,
                                       __global double *partial_sums,
                                       __global double *CDF,
                                       __global double *u,
                                       __global int *seed) {
    int gid = (int)get_global_id(0);
    if (gid != 0) return;

    double sumWeights = partial_sums[0];
    if (sumWeights == 0.0) sumWeights = 1.0;

    double cdf = 0.0;
    for (int i = 0; i < Nparticles; i++) {
        weights[i] = weights[i] / sumWeights;
        cdf += weights[i];
        CDF[i] = cdf;
    }

    double u1 = (1.0 / (double)Nparticles) * randu_kernel(seed, 0);
    for (int i = 0; i < Nparticles; i++) {
        u[i] = u1 + (double)i / (double)Nparticles;
    }
}

