#pragma OPENCL EXTENSION cl_khr_fp64 : enable

inline int findIndex_kernel(__global double *CDF, int lengthCDF, double value) {
    int index = -1;
    for (int x = 0; x < lengthCDF; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1) return lengthCDF - 1;
    return index;
}

__kernel void find_index_kernel(__global double *arrayX,
                                __global double *arrayY,
                                __global double *CDF,
                                __global double *u,
                                __global double *xj,
                                __global double *yj,
                                __global double *weights,
                                int Nparticles) {
    int gid = (int)get_global_id(0);
    if (gid != 0) return;

    for (int j = 0; j < Nparticles; j++) {
        int i = findIndex_kernel(CDF, Nparticles, u[j]);
        if (i == -1) i = Nparticles - 1;
        xj[j] = arrayX[i];
        yj[j] = arrayY[i];
    }

    double w = 1.0 / (double)Nparticles;
    for (int j = 0; j < Nparticles; j++) {
        arrayX[j] = xj[j];
        arrayY[j] = yj[j];
        weights[j] = w;
    }
}
